```

Add `advancedOpen` state:
```tsx
const [advancedOpen, setAdvancedOpen] = useState(false);
```

### 4. Restructure JSX

Replace the entire `<Tabs>` block and standalone URL input with:

1. **Marketplace grid** as primary content (no wrapping tab component)
2. **Advanced collapsible** containing the custom GitHub URL input

### 5. Target Code

```tsx
import { useState } from 'react';
import { Check, ChevronDown } from 'lucide-react';
import {
  Input,
  Label,
  Collapsible,
  CollapsibleTrigger,
  CollapsibleContent,
} from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import { useMarketplacePackages } from '@/layers/entities/marketplace';

interface TemplatePickerProps {
  /** Currently selected marketplace source URL or custom URL — null if nothing selected. */
  selectedTemplate: string | null;
  /** Called when selection changes. Receives source URL or null. */
  onSelect: (template: string | null) => void;
}

/**
 * Template picker showing marketplace agent templates with an Advanced
 * section for custom GitHub URL input.
 */
export function TemplatePicker({ selectedTemplate, onSelect }: TemplatePickerProps) {
  const [customUrl, setCustomUrl] = useState('');
  const [advancedOpen, setAdvancedOpen] = useState(false);
  const { data: marketplaceAgents, error: marketplaceError } = useMarketplacePackages({
    type: 'agent',
  });

  return (
    <div className="space-y-3">
      <Label>Template (optional)</Label>

      {/* Marketplace agent grid */}
      {marketplaceError ? (
        <p className="text-muted-foreground py-8 text-center text-xs">
          Could not load marketplace agents. Check your network and marketplace sources in
          Settings.
        </p>
      ) : (marketplaceAgents ?? []).length === 0 ? (
        <p className="text-muted-foreground py-8 text-center text-xs">
          No marketplace agents available. Add a marketplace source in Settings.
        </p>
      ) : (
        <div className="grid grid-cols-4 gap-2" data-testid="marketplace-template-grid">
          {marketplaceAgents!.map((agent) => (
            <button
              key={agent.name}
              type="button"
              onClick={() => {
                onSelect(selectedTemplate === agent.source ? null : agent.source);
                setCustomUrl('');
              }}
              className={cn(
                'hover:border-primary rounded-lg border p-3 text-left transition-colors',
                selectedTemplate === agent.source && 'border-primary bg-primary/5'
              )}
              data-testid={`marketplace-template-${agent.name}`}
            >
              <p className="text-sm font-medium">{agent.name}</p>
              {agent.description && (
                <p className="text-muted-foreground line-clamp-2 text-xs">
                  {agent.description}
                </p>
              )}
              {selectedTemplate === agent.source && (
                <Check className="text-primary mt-1 size-4" aria-hidden />
              )}
            </button>
          ))}
        </div>
      )}

      {/* Advanced: custom GitHub URL */}
      <Collapsible open={advancedOpen} onOpenChange={setAdvancedOpen}>
        <CollapsibleTrigger asChild>
          <button
            type="button"
            className="text-muted-foreground hover:text-foreground flex w-full items-center gap-1 text-sm transition-colors"
            data-testid="advanced-toggle"
          >
            <ChevronDown
              className={cn('size-4 transition-transform', advancedOpen && 'rotate-180')}
            />
            Advanced
          </button>
        </CollapsibleTrigger>
        <CollapsibleContent>
          <div className="space-y-1 pt-2">
            <p className="text-muted-foreground text-xs">Custom GitHub URL:</p>
            <Input
              value={customUrl}
              onChange={(e) => {
                const url = e.target.value;
                setCustomUrl(url);
                onSelect(url || null);
              }}
              placeholder="github.com/org/repo"
              data-testid="custom-url-input"
            />
          </div>
        </CollapsibleContent>
      </Collapsible>
    </div>
  );
}
```

## Acceptance Criteria

- No built-in template tab or category filter pills
- Marketplace agent grid is the primary (and only) template display
- Grid shows marketplace agents from `useMarketplacePackages({ type: 'agent' })`
- Error state shown when marketplace hook returns error
- Empty state shown when no marketplace agents available
- Clicking a marketplace agent toggles selection (calls `onSelect` with source URL or null)
- "Advanced" collapsible contains the custom GitHub URL input
- Custom URL input is inside the collapsible (not always visible)
- Grid selection and URL input remain mutually exclusive (selecting a template clears URL)
- `TemplatePickerProps` interface unchanged (`selectedTemplate`, `onSelect`)
- No references to `useTemplateCatalog`, `CATEGORY_TABS`, `TemplateCategory`, or built-in template grid remain
- `data-testid="marketplace-template-grid"` preserved for existing test selectors
- `data-testid="custom-url-input"` preserved for existing test selectors
- `data-testid="advanced-toggle"` added for the new collapsible trigger

